import java.util.*

fun solve(nums: Array<Long>): Long {
    val n = nums.size
    val dist = LongArray(n).apply { fill(0L) }
    val visited = BooleanArray(n).apply { fill(false) }
    val queue = LinkedList<Int>()

    queue.add(0)
    dist[0] = 0L
    visited[0] = true

    // Precompute primes up to the maximum possible value in nums
    val maxNum = nums.maxOrNull() ?: 1L
    val sieve = BooleanArray(maxNum.toInt() + 1) { it >= 2 }

    for (i in 2..sieve.size - 1) {
        sieve[i] = true
        for (j in i * 2 until sieve.size step i) {
            sieve[j] = false
        }
    }

    while (queue.isNotEmpty()) {
        val i = queue.poll()
        val val = nums[i]

        if (i == n - 1) {
            return dist[i]
        }

        // Move to adjacent cells
        for (j in listOf(i - 1, i + 1)) {
            if (j in 0..n - 1 && !visited[j]) {
                visited[j] = true
                dist[j] = dist[i] + 1
                queue.add(j)
            }
        }

        // If the current value is a prime, perform prime teleport
        if (val > 1L && sieve[val.toInt()]) {
            for (j in 0..n - 1) {
                if (j != i && nums[j] % val == 0 && !visited[j]) {
                    visited[j] = true
                    dist[j] = dist[i] + 1
                    queue.add(j)
                }
            }
        }
    }

    return -1L
}
